from dataclasses import dataclass

@dataclass
class DifficultyTier:
    name: str
    min_score: float
    max_score: float  # difficulty score range for this tier
    n_steps: int      # number of training steps to spend at this tier

class StepwiseSchedule:
    def __init__(self, tiers: list[DifficultyTier]):
        self.tiers = tiers
        # Build step boundaries
        self.boundaries = []
        cumulative = 0
        for tier in tiers:
            cumulative += tier.n_steps
            self.boundaries.append(cumulative)

    def current_tier(self, step: int) -> DifficultyTier:
        for tier, boundary in zip(self.tiers, self.boundaries):
            if step < boundary:
                return tier
        return self.tiers[-1]  # past all boundaries: use hardest tier

    def select(self, dataset: list[dict], step: int,
                score_field: str = 'difficulty') -> list[dict]:
        tier = self.current_tier(step)
        return [
            ex for ex in dataset
            if tier.min_score <= ex.get(score_field, 0.5) < tier.max_score
        ]


