class DynamicDifficultyEstimator:
    """
    Tracks per-example difficulty dynamically from training loss.
    Uses exponential moving average (EMA) of per-example loss.
    """
    def __init__(self, dataset_size: int, ema_alpha: float = 0.1):
        self.loss_ema = [0.5] * dataset_size  # initialise at medium difficulty
        self.alpha    = ema_alpha
        self.n_seen   = [0] * dataset_size

    def update(self, indices: list[int], losses: list[float]):
        """Update EMA loss for each training example by its index."""
        for idx, loss in zip(indices, losses):
            if self.n_seen[idx] == 0:
                self.loss_ema[idx] = loss
            else:
                self.loss_ema[idx] = (
                    self.alpha * loss + (1 - self.alpha) * self.loss_ema[idx]
                )
            self.n_seen[idx] += 1

    def difficulty(self, idx: int) -> float:
        """Normalised difficulty score in [0, 1]."""
        losses = [l for l, n in zip(self.loss_ema, self.n_seen) if n > 0]
        if not losses:
            return 0.5
        min_l, max_l = min(losses), max(losses)
        if max_l == min_l:
            return 0.5
        return (self.loss_ema[idx] - min_l) / (max_l - min_l)

    def easiest_fraction(self, fraction: float) -> list[int]:
        """Return indices of the easiest `fraction` of seen examples."""
        seen_idx = [i for i, n in enumerate(self.n_seen) if n > 0]
        seen_idx.sort(key=lambda i: self.loss_ema[i])
        n = max(1, int(fraction * len(seen_idx)))
        return seen_idx[:n]

import ast

def cyclomatic_complexity(code: str) -> int:
    """
    Estimate cyclomatic complexity of a Python function.
    Counts decision points: if, elif, for, while, and, or, except, with.
    Returns 1 (simplest) or higher.
    """
    try:
        tree = ast.parse(code)
    except SyntaxError:
        return 10  # unparseable = treat as complex

    decision_nodes = (
        ast.If, ast.For, ast.While, ast.ExceptHandler,
        ast.With, ast.BoolOp, ast.comprehension
    )
    count = 1
    for node in ast.walk(tree):
        if isinstance(node, decision_nodes):
            count += 1
        elif isinstance(node, ast.BoolOp):
            count += len(node.values) - 1
    return count


def score_code_dataset(examples: list[dict],
                         code_field: str = 'canonical_solution') -> list[dict]:
    """Add cyclomatic complexity as difficulty score to each code example."""
    max_complexity = 1
    for ex in examples:
        cc = cyclomatic_complexity(ex.get(code_field, ''))
        ex['difficulty'] = cc
        max_complexity = max(max_complexity, cc)

    # Normalise to [0, 1]
    for ex in examples:
        ex['difficulty'] /= max_complexity

    return sorted(examples, key=lambda x: x['difficulty'])
